document.addEventListener("DOMContentLoaded",function(){const modalidade="triathlon";console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Script carregado e DOM pronto.`);const formCadastro=document.getElementById(`cadastro-form-${modalidade}`);if(!formCadastro){console.error(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Formulário principal #cadastro-form-${modalidade} não encontrado.`);return}const nomeInput=document.getElementById(`nome-${modalidade}`);const telefoneInput=document.getElementById(`whatsapp-${modalidade}`);const planoSelect=document.getElementById(`plano-${modalidade}`);const periodicidadeSelect=document.getElementById(`periodicidade-${modalidade}`);const treinadorSelect=document.getElementById(`treinador-${modalidade}`);const termosCheckbox=document.getElementById(`termos-${modalidade}`);if(!nomeInput||!telefoneInput||!planoSelect||!periodicidadeSelect||!treinadorSelect||!termosCheckbox){console.error(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Um ou mais campos do formulário não foram encontrados. Verifique os IDs.`);return}console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Todos os campos do formulário foram encontrados.`);const treinadoresTriathlon={essencial:["Jéssica Rodrigues","Thais Prando"],premium:["Jéssica Rodrigues","Thais Prando","Elinai Freitas"]};const tecnoFitLinksTriathlon={essencial:{mensal:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTEy",trimestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTE2",semestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTE3"},premium:{mensal:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTIx",trimestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTIy",semestral:"https://app.tecnofit.com.br/ng/online-sale/MjA5NjA/checkout/OTk5MTI1"}};console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Links Tecnofit (Triathlon) definidos:`,JSON.stringify(tecnoFitLinksTriathlon));function popularTreinadores(){treinadorSelect.innerHTML=`<option value="">Selecione o Treinador</option>`;const planoSelecionadoValor=planoSelect.value;let tipoPlano="";if(planoSelecionadoValor.toLowerCase().includes("essencial"))tipoPlano="essencial";else if(planoSelecionadoValor.toLowerCase().includes("premium"))tipoPlano="premium";console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Populando treinadores para plano: ${planoSelecionadoValor} (tipo derivado: ${tipoPlano})`);if(tipoPlano&&treinadoresTriathlon[tipoPlano]){treinadoresTriathlon[tipoPlano].forEach(treinador=>{const option=document.createElement("option");option.value=treinador.toLowerCase().replace(/\s+/g,"-");option.textContent=treinador;treinadorSelect.appendChild(option)})}else if(planoSelecionadoValor){console.warn(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Tipo de plano não reconhecido ('${tipoPlano}') para popular treinadores. Plano selecionado: ${planoSelecionadoValor}`)}else{console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Nenhum plano selecionado, lista de treinadores permanece com 'Selecione'.`)}}planoSelect.addEventListener("change",popularTreinadores);popularTreinadores();formCadastro.addEventListener("submit",function(event){event.preventDefault();console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Formulário submetido.`);if(!nomeInput.value.trim()){alert("Por favor, preencha o nome completo.");return}if(!telefoneInput.value.trim()){alert("Por favor, preencha o WhatsApp.");return}if(!planoSelect.value){alert("Por favor, selecione um plano.");return}if(!periodicidadeSelect.value){alert("Por favor, selecione uma periodicidade.");return}if(!treinadorSelect.value){alert("Por favor, selecione um treinador.");return}if(!termosCheckbox.checked){alert("Por favor, aceite os termos de contrato.");return}console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Validações passaram.`);const planoSelecionadoOriginal=planoSelect.value;const periodicidadeSelecionada=periodicidadeSelect.value.toLowerCase();let tipoPlanoChave="";if(planoSelecionadoOriginal.toLowerCase().includes("essencial"))tipoPlanoChave="essencial";else if(planoSelecionadoOriginal.toLowerCase().includes("premium"))tipoPlanoChave="premium";console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Buscando link para: tipoPlanoChave='${tipoPlanoChave}', periodicidade='${periodicidadeSelecionada}'`);let checkoutUrl="#";if(tipoPlanoChave&&tecnoFitLinksTriathlon[tipoPlanoChave]&&tecnoFitLinksTriathlon[tipoPlanoChave][periodicidadeSelecionada]){checkoutUrl=tecnoFitLinksTriathlon[tipoPlanoChave][periodicidadeSelecionada];console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] URL Tecnofit (Triathlon) encontrada: ${checkoutUrl}`)}else{console.error(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] ERRO: URL Tecnofit (Triathlon) NÃO encontrada para tipoPlanoChave='${tipoPlanoChave}', periodicidade='${periodicidadeSelecionada}'.`);alert("Erro ao processar sua solicitação. Link de checkout não encontrado para a combinação selecionada. Por favor, contate o suporte.");return}const formData=new FormData(formCadastro);formData.append("modalidade_pagina","Triathlon");formData.append("plano_selecionado_detalhe",planoSelecionadoOriginal);formData.append("periodicidade_selecionada_detalhe",periodicidadeSelect.options[periodicidadeSelect.selectedIndex].text);formData.append("treinador_selecionado_detalhe",treinadorSelect.options[treinadorSelect.selectedIndex].text);console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Enviando para Formspree (${formCadastro.action}):`,Object.fromEntries(formData));fetch(formCadastro.action,{method:"POST",body:formData,headers:{Accept:"application/json"}}).then(response=>{if(response.ok){console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Sucesso no envio para Formspree.`)}else{response.json().then(data=>{if(data.errors){console.error(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Erro do Formspree:`,data.errors.map(e=>e.message).join(", "))}else{console.error(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Erro desconhecido do Formspree. Status: ${response.status}`)}})}}).catch(error=>{console.error(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Erro de rede ao enviar para Formspree:`,error)}).finally(()=>{if(checkoutUrl!=="#"){console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Abrindo Tecnofit em nova aba: ${checkoutUrl}`);window.open(checkoutUrl,"_blank")}else{console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] URL de checkout era '#', não redirecionando.`)}})});console.log(`[RECONSTRUÍDO - ${modalidade.toUpperCase()}] Script totalmente inicializado.`)});